package main

import (
	"crypto/rand"
	"encoding/hex"
	"errors"
	"net/http"
	"net/url"
	"strings"

	"golang.org/x/oauth2"
)

var OAuthConfig = &oauth2.Config{
	ClientID:     "your-client-id",
	ClientSecret: "your-client-secret",
	RedirectURL:  "https://yourapp.com/callback",
	Scopes:       []string{"openid", "profile", "email"},
	Endpoint: oauth2.Endpoint{
		AuthURL:  "https://provider.com/oauth2/authorize",
		TokenURL: "https://provider.com/oauth2/token",
	},
}

// GenerateAuthURL generates an OAuth2 authorization URL for the user to authenticate.
// The redirectPath parameter allows customization of where the user should be redirected after auth.
func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// Generate cryptographically random state
	stateBytes := make([]byte, 32)
	if _, err := rand.Read(stateBytes); err != nil {
		return "", errors.New("failed to generate state: " + err.Error())
	}
	state := hex.EncodeToString(stateBytes)

	// Validate redirect path
	validatedRedirectURL, err := validateRedirectPath(redirectPath)
	if err != nil {
		return "", err
	}

	// Create a copy of the OAuth config with the validated redirect URL
	config := *OAuthConfig
	config.RedirectURL = validatedRedirectURL

	// Generate the authorization URL
	authURL := config.AuthCodeURL(state)

	// Set the state in a secure cookie for later validation
	http.SetCookie(w, &http.Cookie{
		Name:     "oauth_state",
		Value:    state,
		HttpOnly: true,
		Secure:   true,
		SameSite: http.SameSiteStrictMode,
		Path:     "/",
		MaxAge:   600, // 10 minutes
	})

	return authURL, nil
}

// validateRedirectPath validates and sanitizes the redirect path to prevent open redirect vulnerabilities
func validateRedirectPath(redirectPath string) (string, error) {
	// Default to root path if empty
	if redirectPath == "" {
		return "/", nil
	}

	// Ensure path starts with /
	if !strings.HasPrefix(redirectPath, "/") {
		return "", errors.New("redirect path must start with /")
	}

	// Parse and validate the path
	parsedURL, err := url.Parse(redirectPath)
	if err != nil {
		return "", errors.New("invalid redirect path: " + err.Error())
	}

	// Ensure no scheme or host is specified (prevent open redirect)
	if parsedURL.Scheme != "" || parsedURL.Host != "" {
		return "", errors.New("redirect path must be a relative path")
	}

	// Sanitize path to prevent path traversal
	cleanedPath := parsedURL.Path
	if cleanedPath == "" {
		cleanedPath = "/"
	}

	// Validate against whitelist of allowed paths
	allowedPaths := map[string]bool{
		"/":                 true,
		"/home":             true,
		"/dashboard":        true,
		"/profile":          true,
		"/settings":         true,
		"/callback":         true,
	}

	if !allowedPaths[cleanedPath] {
		return "", errors.New("redirect path is not allowed")
	}

	return cleanedPath, nil
}

