// GenerateAuthURL generates an OAuth2 authorization URL for the user to authenticate.
// The redirectPath parameter allows customization of where the user should be redirected after auth.
func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// Create a copy of the OAuth config to avoid modifying the global config
	config := &oauth2.Config{
		ClientID:     OAuthConfig.ClientID,
		ClientSecret: OAuthConfig.ClientSecret,
		RedirectURL:  OAuthConfig.RedirectURL,
		Scopes:       OAuthConfig.Scopes,
		Endpoint:     OAuthConfig.Endpoint,
	}

	// Handle the redirectPath parameter
	if redirectPath != "" {
		// Check if redirectPath is a full URL or a relative path
		if strings.HasPrefix(redirectPath, "http://") || strings.HasPrefix(redirectPath, "https://") {
			// It's a full URL, use it directly
			config.RedirectURL = redirectPath
		} else {
			// It's a relative path, combine with the base URL from the original RedirectURL
			originalURL, err := url.Parse(OAuthConfig.RedirectURL)
			if err != nil {
				return "", err
			}

			// Ensure the redirectPath starts with '/'
			if !strings.HasPrefix(redirectPath, "/") {
				redirectPath = "/" + redirectPath
			}

			// Combine the base URL with the redirect path
			newURL := &url.URL{
				Scheme: originalURL.Scheme,
				Host:   originalURL.Host,
				Path:   redirectPath,
			}
			config.RedirectURL = newURL.String()
		}
	}

	// Generate the authorization URL with a random state parameter
	state := randomState()
	authURL := config.AuthCodeURL(state)

	// Set the session cookie if provided
	if session != nil {
		http.SetCookie(w, session)
	}

	// Redirect the user to the authorization URL
	http.Redirect(w, r, authURL, http.StatusTemporaryRedirect)

	return authURL, nil
}

// randomState generates a random state string for OAuth2 security
func randomState() string {
	return "random_state_string"
}

