package main

import (
	"crypto/rand"
	"encoding/base64"
	"fmt"
	"net/http"
	"strings"
	"time"

	"golang.org/x/oauth2"
)

var OAuthConfig = &oauth2.Config{
	ClientID:     "your-client-id",
	ClientSecret: "your-client-secret",
	RedirectURL:  "https://yourapp.com/callback",
	Scopes:       []string{"openid", "profile", "email"},
	Endpoint: oauth2.Endpoint{
		AuthURL:  "https://provider.com/oauth2/authorize",
		TokenURL: "https://provider.com/oauth2/token",
	},
}

// GenerateAuthURL generates an OAuth2 authorization URL for the user to authenticate.
// The redirectPath parameter allows customization of where the user should be redirected after auth.
func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// Generate a cryptographically secure random state
	state, err := generateSecureState()
	if err != nil {
		return "", fmt.Errorf("failed to generate state: %w", err)
	}

	// Construct the full redirect URL from the path
	redirectURL, err := constructRedirectURL(redirectPath, r)
	if err != nil {
		return "", fmt.Errorf("failed to construct redirect URL: %w", err)
	}

	// Create a copy of the OAuth config with the custom redirect URL
	config := *OAuthConfig
	config.RedirectURL = redirectURL

	// Generate the authorization URL
	authURL := config.AuthCodeURL(state)

	// Set the state in a cookie for later validation
	http.SetCookie(w, &http.Cookie{
		Name:     "oauth_state",
		Value:    state,
		HttpOnly: true,
		Secure:   isSecureConnection(r),
		SameSite: http.SameSiteLaxMode,
		Path:     "/",
		Expires:  time.Now().Add(10 * time.Minute), // State should expire after 10 minutes
	})

	return authURL, nil
}

// generateSecureState creates a cryptographically secure random state string
func generateSecureState() (string, error) {
	b := make([]byte, 32)
	_, err := rand.Read(b)
	if err != nil {
		return "", err
	}
	return base64.URLEncoding.EncodeToString(b), nil
}

// constructRedirectURL builds the full redirect URL from the path
func constructRedirectURL(redirectPath string, r *http.Request) (string, error) {
	if redirectPath == "" {
		return "", fmt.Errorf("redirect path cannot be empty")
	}

	// Get the base URL scheme and host
	scheme := "https"
	if r.TLS != nil {
		scheme = "https"
	} else if proto := r.Header.Get("X-Forwarded-Proto"); proto != "" {
		scheme = strings.Split(proto, ",")[0]
	}

	host := r.Host
	if host == "" {
		return "", fmt.Errorf("request host is empty")
	}

	// Ensure redirect path starts with /
	if !strings.HasPrefix(redirectPath, "/") {
		redirectPath = "/" + redirectPath
	}

	return fmt.Sprintf("%s://%s%s", scheme, host, redirectPath), nil
}

// isSecureConnection determines if the connection is secure (HTTPS)
func isSecureConnection(r *http.Request) bool {
	if r.TLS != nil {
		return true
	}
	proto := r.Header.Get("X-Forwarded-Proto")
	return strings.Contains(proto, "https")
}

