// GenerateAuthURL generates an OAuth2 authorization URL for the user to authenticate.
// The redirectPath parameter allows customization of where the user should be redirected after auth.
func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// Validate and adjust redirectPath
	if redirectPath == "" {
		redirectPath = "/"
	} else if !strings.HasPrefix(redirectPath, "/") {
		return "", fmt.Errorf("redirectPath must start with '/'")
	}

	// Generate random state
	b := make([]byte, 32)
	if _, err := rand.Read(b); err != nil {
		return "", err
	}
	state := hex.EncodeToString(b)

	// Set state cookie
	cookie := &http.Cookie{
		Name:     "oauth_state",
		Value:    state,
		Path:     "/",
		HttpOnly: true,
		Secure:   r != nil && r.URL != nil && r.URL.Scheme == "https",
		Expires:  time.Now().Add(10 * time.Minute),
	}
	http.SetCookie(w, cookie)

	// Create config copy with custom redirect URL
	configCopy := *OAuthConfig
	baseURL, err := url.Parse(configCopy.RedirectURL)
	if err != nil {
		return "", err
	}
	baseURL.Path = redirectPath
	configCopy.RedirectURL = baseURL.String()

	return configCopy.AuthCodeURL(state), nil
}

