	},
}

// GenerateAuthURL generates an OAuth2 authorization URL for the user to authenticate.
// The redirectPath parameter allows customization of where the user should be redirected after auth.
func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// Parse the base URL from the existing RedirectURL
	baseURL, err := url.Parse(OAuthConfig.RedirectURL)
	if err != nil {
		return "", fmt.Errorf("failed to parse base redirect URL: %w", err)
	}

	// Construct the new redirect URL by combining base URL with custom path
	var redirectURL string
	if redirectPath == "" {
		redirectURL = OAuthConfig.RedirectURL
	} else {
		// Handle different path formats
		if redirectPath[0] == '/' {
			redirectURL = baseURL.Scheme + "://" + baseURL.Host + redirectPath
		} else {
			redirectURL = baseURL.Scheme + "://" + baseURL.Host + "/" + redirectPath
		}
	}

	// Create a new config with the custom redirect URL
	config := &oauth2.Config{
		ClientID:     OAuthConfig.ClientID,
		ClientSecret: OAuthConfig.ClientSecret,
		RedirectURL:  redirectURL,
		Scopes:       OAuthConfig.Scopes,
		Endpoint:     OAuthConfig.Endpoint,
	}

	// Generate the authorization URL with a state parameter
	// In production, you should generate a cryptographically secure state
	// and store it in the session for validation during callback
	state := "random-state-string"
	authURL := config.AuthCodeURL(state)

	return authURL, nil
}

